import { Routes } from '@angular/router';
import { authGuard } from './core/guards/auth.guard';
import { FlowRoute } from './flow-meta';

// `data.flow` is the single source of truth for the user-flow graph AND the runtime navbar.
// The colossus flow-graph extractor projects it directly (zero heuristics). Authoring rules
// + lint: docs/flow-graph-convention.md + platform/flowgraph-static/verify/flow-lint.mjs.
//
// DEEP-LINKABLE STATE — every navigable UI state a user could leave feedback on must be
// reachable by URL. In this app:
//   • public feed → filter + page via `?category=<name>&page=<n>` (queryParamsHandling:'merge')
//   • admin sources → add modal via `?modal=add-source`
//   • admin categories → add modal via `?modal=add-category`
export const routes: Routes = ([
  {
    path: '',
    loadComponent: () =>
      import('./features/feed/feed.component').then((m) => m.FeedComponent),
    data: {
      flow: {
        flowId: 'feed',
        node: 'feed',
        entry: true,
        showInNavbar: true,
        label: 'Feed',
        scope: 'all',
        edgesTo: ['admin-login'],
      },
    },
  },
  {
    path: 'admin/login',
    loadComponent: () =>
      import('./features/admin/login/admin-login.component').then((m) => m.AdminLoginComponent),
    data: {
      flow: {
        flowId: 'admin-login',
        node: 'admin-login',
        label: 'Admin Login',
        edgesTo: ['admin-dashboard'],
      },
    },
  },
  {
    path: 'admin',
    loadComponent: () =>
      import('./features/admin/admin-layout/admin-layout.component').then(
        (m) => m.AdminLayoutComponent,
      ),
    canActivate: [authGuard],
    data: {
      flow: {
        flowId: 'admin',
        node: 'admin',
        label: 'Admin',
        scope: 'admin',
        edgesTo: ['admin-dashboard'],
      },
    },
    children: [
      {
        path: '',
        loadComponent: () =>
          import('./features/admin/dashboard/admin-dashboard.component').then(
            (m) => m.AdminDashboardComponent,
          ),
        data: {
          flow: {
            flowId: 'admin-dashboard',
            node: 'admin-dashboard',
            showInNavbar: true,
            label: 'Dashboard',
            scope: 'admin',
            edgesTo: ['admin-sources', 'admin-categories', 'feed'],
          },
        },
      },
      {
        path: 'sources',
        loadComponent: () =>
          import('./features/admin/sources/admin-sources.component').then(
            (m) => m.AdminSourcesComponent,
          ),
        data: {
          flow: {
            flowId: 'admin-sources',
            node: 'admin-sources',
            showInNavbar: true,
            label: 'Sources',
            scope: 'admin',
            edgesTo: ['admin-dashboard', 'admin-categories'],
          },
        },
      },
      {
        path: 'categories',
        loadComponent: () =>
          import('./features/admin/categories/admin-categories.component').then(
            (m) => m.AdminCategoriesComponent,
          ),
        data: {
          flow: {
            flowId: 'admin-categories',
            node: 'admin-categories',
            showInNavbar: true,
            label: 'Categories',
            scope: 'admin',
            edgesTo: ['admin-dashboard', 'admin-sources'],
          },
        },
      },
    ],
  },
  { path: '**', redirectTo: '' },
] satisfies FlowRoute[]) as Routes;
